package cl.duoc.vetcontrol.venta.model;
import com.fasterxml.jackson.annotation.JsonIgnore; import jakarta.persistence.*; import java.math.BigDecimal;
@Entity @Table(name="detalle_venta")
public class DetalleVenta { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="venta_id", nullable=false) @JsonIgnore private Venta venta; @Column(nullable=false) private Long productoId; @Column(nullable=false) private Integer cantidad; @Column(nullable=false,precision=10,scale=2) private BigDecimal precioUnitario; @Column(nullable=false,precision=12,scale=2) private BigDecimal subtotal; public Long getId(){return id;} public void setId(Long id){this.id=id;} public Venta getVenta(){return venta;} public void setVenta(Venta venta){this.venta=venta;} public Long getProductoId(){return productoId;} public void setProductoId(Long productoId){this.productoId=productoId;} public Integer getCantidad(){return cantidad;} public void setCantidad(Integer cantidad){this.cantidad=cantidad;} public BigDecimal getPrecioUnitario(){return precioUnitario;} public void setPrecioUnitario(BigDecimal precioUnitario){this.precioUnitario=precioUnitario;} public BigDecimal getSubtotal(){return subtotal;} public void setSubtotal(BigDecimal subtotal){this.subtotal=subtotal;} }
